/* ===========================================================================
 * mockResponse helper characterization
 *
 * `mockResponse` (defined at the top of this file) is shared test
 * infrastructure that builds a minimal fetch `Response` stand-in for the
 * stubbed global `fetch`. An effectively-identical copy also lives inline in
 * `src/app.test.ts`; the two copies differ ONLY in `json()`'s fallback for
 * the text-only case — this file parses the text as JSON, app.test.ts returns
 * `{}`. This suite pins down the UNION semantics (the more capable variant,
 * which is what the extracted shared module should adopt) so that when the
 * helper is deduplicated into a shared module both call sites keep working
 * without behavioral drift.
 *
 * These tests intentionally target the branches the behavioral ApiClient
 * tests above do NOT exercise: on the error path ApiClient only calls
 * `.text()` (never `.json()`), and on the success path a `body` is always
 * supplied — so the `ok` derivation, the `text()` default, and every `json()`
 * fallback (null/undefined body → {}, text-only → parsed JSON, body-wins-over-
 * text, primitive/nullish `body` passthrough) are otherwise uncharacterized.
 *
 * They live here (next to the union copy) and pass against the CURRENT inline
 * implementation; after the helper is extracted into a shared module and this
 * file imports it, the same assertions validate the shared implementation.
 * ========================================================================= */
describe('mockResponse helper', () => {
  describe('status and ok', () => {
    it('defaults status to 200 and ok to true', () => {
      const res = mockResponse({});
      expect(res.status).toBe(200);
      expect(res.ok).toBe(true);
    });

    it('derives ok=true for every 2xx status', () => {
      for (const status of [200, 201, 204, 299]) {
        expect(mockResponse({ status }).ok).toBe(true);
      }
    });

    it('derives ok=false for every non-2xx status (including 3xx redirects)', () => {
      for (const status of [301, 400, 404, 500, 503]) {
        expect(mockResponse({ status }).ok).toBe(false);
      }
    });

    it('preserves an explicit status on the response', () => {
      expect(mockResponse({ status: 418 }).status).toBe(418);
    });

    it('an explicit ok=true overrides a status that would otherwise be not-ok', () => {
      expect(mockResponse({ ok: true, status: 500 }).ok).toBe(true);
    });

    it('an explicit ok=false overrides a status that would otherwise be ok (nullish, not falsy, coalescing)', () => {
      // Guards against a future bug where `ok ?? derived` is accidentally
      // rewritten as `ok || derived`, which would ignore an explicit false.
      expect(mockResponse({ ok: false, status: 200 }).ok).toBe(false);
    });
  });

  describe('text()', () => {
    it('returns the explicit text when provided', async () => {
      expect(await mockResponse({ text: 'Not Found' }).text()).toBe('Not Found');
    });

    it('defaults to JSON.stringify(body) when no text is given', async () => {
      expect(await mockResponse({ body: { a: 1 } }).text()).toBe(JSON.stringify({ a: 1 }));
    });

    it('defaults to "{}" when neither body nor text is given', async () => {
      expect(await mockResponse({}).text()).toBe('{}');
    });

    it('defaults to "{}" when body is null', async () => {
      expect(await mockResponse({ body: null }).text()).toBe('{}');
    });

    it('uses the explicit text verbatim even when a body is also present', async () => {
      // The error path relies on this: mockResponse({ status: 404, text: 'Not Found' })
      // must surface 'Not Found' via .text(), NOT the JSON-stringified body.
      expect(await mockResponse({ body: { a: 1 }, text: 'Not Found' }).text()).toBe('Not Found');
    });

    it('serializes a primitive body when no text is given', async () => {
      expect(await mockResponse({ body: 0 }).text()).toBe('0');
    });
  });

  describe('json()', () => {
    it('returns the body object when provided', async () => {
      const body = { path: '/x', entries: [1, 2, 3] };
      expect(await mockResponse({ body }).json()).toEqual(body);
    });

    it('returns the body array when provided', async () => {
      expect(await mockResponse({ body: [1, 2, 3] }).json()).toEqual([1, 2, 3]);
    });

    it('returns a string body unchanged', async () => {
      expect(await mockResponse({ body: 'hello' }).json()).toBe('hello');
    });

    it('returns a falsy-but-defined numeric body unchanged (nullish coalescing, not ||)', async () => {
      // `body ?? fallback` must keep 0; `body || fallback` would drop it.
      expect(await mockResponse({ body: 0 }).json()).toBe(0);
    });

    it('returns a falsy-but-defined boolean body unchanged', async () => {
      expect(await mockResponse({ body: false }).json()).toBe(false);
    });

    it('returns {} when body is null', async () => {
      // app.test.ts uses mockResponse({ status: 204, body: null }) for the
      // delete endpoint; the shared module must keep mapping null → {}.
      expect(await mockResponse({ body: null }).json()).toEqual({});
    });

    it('returns {} when body is undefined', async () => {
      expect(await mockResponse({ body: undefined }).json()).toEqual({});
    });

    it('returns {} when neither body nor text is given', async () => {
      expect(await mockResponse({}).json()).toEqual({});
    });

    it('parses the text as JSON when only text is provided (UNION behavior)', async () => {
      // This is the one branch where the api.test.ts and app.test.ts copies
      // differ: this copy (api) parses; app.test.ts would return {}. The shared
      // module adopts the union (parse) semantics.
      expect(await mockResponse({ text: '{"a":1,"b":2}' }).json()).toEqual({ a: 1, b: 2 });
    });

    it('prefers body over text when both are provided', async () => {
      expect(await mockResponse({ body: { a: 1 }, text: '{"z":9}' }).json()).toEqual({ a: 1 });
    });
  });

  describe('async shape and Response-like surface', () => {
    it('text() and json() each return a Promise', () => {
      const res = mockResponse({ body: { a: 1 } });
      expect(res.text()).toBeInstanceOf(Promise);
      expect(res.json()).toBeInstanceOf(Promise);
    });

    it('awaits to the same values across repeated reads (idempotent accessors)', async () => {
      const res = mockResponse({ body: { a: 1 }, text: 'literal' });
      expect(await res.text()).toBe('literal');
      expect(await res.text()).toBe('literal');
      expect(await res.json()).toEqual({ a: 1 });
      expect(await res.json()).toEqual({ a: 1 });
    });

    it('exposes ok (boolean), status (number), and async text/json accessors', async () => {
      const res = mockResponse({ status: 404, text: 'Not Found' });
      expect(typeof res.ok).toBe('boolean');
      expect(typeof res.status).toBe('number');
      expect(typeof res.text).toBe('function');
      expect(typeof res.json).toBe('function');
      expect(await res.text()).toBe('Not Found');
    });
  });
});

/**
 * Tests for `src/app.ts` — the SPA entry that wires `api` + `router` + DOM.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * This module is being developed test-first, so the assertions below pin the
 * observable contract from the task spec. Where the spec left the exact
 * mechanism open, these contract decisions are encoded and documented inline:
 *
 *  - In-app navigation (directory links, the ".." parent row, breadcrumb
 *    segments, search-result directory names) is verified by asserting on
 *    `window.location.hash` after a click. This is robust to either
 *    implementation strategy: a click handler that calls `navigate(...)`, or an
 *    `<a href="#...">` (happy-dom follows hash-fragment href clicks).
 *  - Clicking a search-result FILE name opens its download URL. The spec does
 *    not pin the mechanism, so that test accepts EITHER an
 *    `<a href={downloadUrl}>` OR a `window.open(downloadUrl)` call.
 *  - The action controls Delete / Move / Copy are `<button>` elements whose
 *    trimmed `textContent` is exactly `"Delete"` / `"Move"` / `"Copy"`.
 *  - `renderBrowse` / `renderSearch` operate against the DOM context that
 *    `startApp` establishes (module-level element references), so every test
 *    calls `setup()` first.
 *  - The results table uses a `<thead>` (header `<th>` row) and a `<tbody>`
 *    (data `<td>` rows). Column order for browse is
 *    `Name | Size | Modified | Actions`; for search `Name | Path | Size |
 *    Modified`.
 */
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { startApp, renderBrowse, renderSearch } from './app';
import type { BrowseResult, FileEntry, SearchResult } from './api';
import type { Route } from './router';
import { toBrowseHash, toSearchHash, navigate } from './router';
import { normalizeRelativePath, formatBytes } from './format';

/* ===========================================================================
 * Shared helpers
 * ========================================================================= */

/** Minimal fetch `Response` stand-in for the stubbed global `fetch`. */
function mockResponse(opts: {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => (opts.body ?? {}),
  } as unknown as Response;
}

const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
  };
}

function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

const browseRoute = (path: string): Route => ({ view: 'browse', path, query: '' });
const searchRoute = (query: string, path = ''): Route => ({ view: 'search', query, path });

/** Let pending microtasks / queued hashchange renders settle. */
const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

interface SetupCtx {
  root: HTMLElement;
  embeddedHost: HTMLElement;
  widget: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchBtn: HTMLButtonElement;
  uploadLabel: HTMLLabelElement;
  uploadInput: HTMLInputElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  const button = (text: string): HTMLButtonElement | undefined =>
    Array.from(root.querySelectorAll('button')).find(
      (b) => (b.textContent ?? '').trim() === text,
    ) as HTMLButtonElement | undefined;

  return {
    root,
    embeddedHost: root.querySelector('.file-browser-host') as HTMLElement,
    widget: root.querySelector('.file-browser') as HTMLElement,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: root.querySelector('.close-btn') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchBtn: button('Search') as HTMLButtonElement,
    uploadLabel: root.querySelector('label.btn') as HTMLLabelElement,
    uploadInput: root.querySelector('input[type="file"]') as HTMLInputElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* Table-traversal helpers (browser-agnostic; work on Element). */
function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find(
    (tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name,
  );
}
function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Test lifecycle
 * ========================================================================= */

let fetchMock: ReturnType<typeof vi.fn>;

beforeEach(() => {
  // A permissive default: every browse/search GET returns a recognizable result
  // derived from the requested path/query, and every mutation returns 200.
  // Individual tests override with `fetchMock.mockImplementation(...)` or
  // `.mockResolvedValueOnce(...)` for specific scenarios. This also means
  // incidental background renders (e.g. from accumulated hashchange listeners)
  // never throw unhandled rejections.
  fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
    const u = String(url);
    const method = (init?.method ?? 'GET').toUpperCase();
    if (method === 'GET' && u.includes('/browse')) {
      const raw = u.split('path=')[1] ?? '';
      const path = decodeURIComponent(raw);
      const childName = 'child-of-' + (path || 'root');
      return mockResponse({
        body: browseResult({
          path,
          entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
          fileCount: 1,
          totalSize: 10,
        }),
      });
    }
    if (method === 'GET' && u.includes('/search')) {
      const afterQuery = u.slice(u.indexOf('query=') + 6);
      const query = decodeURIComponent(afterQuery.split('&')[0]);
      return mockResponse({
        body: {
          query,
          path: '',
          results: [fileEntry({ name: 'result-for-' + query, path: joinPathHelper('docs', 'result-for-' + query) })],
        } as SearchResult,
      });
    }
    return mockResponse({ status: 200, body: {} });
  });
  vi.stubGlobal('fetch', fetchMock);
});

afterEach(() => {
  // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
  // location.hash dispatches `hashchange` synchronously. startApp unsubscribes
  // the previous mount's render() listener on re-mount (so listeners no longer
  // accumulate across tests), but the CURRENT test's listener remains active
  // until the next test's setup() re-mounts. Resetting the hash after
  // `vi.unstubAllGlobals()` would therefore drive a render through the REAL
  // fetch. We clear the body first (while fetch is still stubbed, so any
  // in-flight render's already-issued request stays mocked) and reset the hash
  // at the start of the next test's setup() instead.
  document.body.innerHTML = '';
  vi.unstubAllGlobals();
  vi.restoreAllMocks();
});

